import 'dart:math';

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';

/// Generates one randomized value for a fractal parameter schema.
///
/// This pure helper keeps the controller's randomization data flow visible and
/// replayable in tests without depending on FractalController state. Returned
/// values are normalized through the same schema contract used for presets,
/// replayed state, and direct UI updates.
Object randomFractalParamValue(FractalParameter param, Random random) {
  switch (param.type) {
    case FractalParamType.float:
      final raw = param.min + random.nextDouble() * (param.max - param.min);
      return normalizeFractalParamValue(
        param,
        roundFractalParamValueToStep(raw, param.step),
      );
    case FractalParamType.integer:
      final bounds = FractalNumericParamBounds.fromSchema(param);
      assert(
        bounds.containsInteger,
        'integer parameter bounds must include at least one integer value',
      );
      if (!bounds.containsInteger) {
        return normalizeFractalParamValue(param, param.defaultValue);
      }
      final min = bounds.min.ceil();
      final max = bounds.max.floor();
      return normalizeFractalParamValue(
        param,
        min + random.nextInt(max - min + 1),
      );
    case FractalParamType.enumeration:
      if (param.options.isNotEmpty) {
        final choice = param.options[random.nextInt(param.options.length)];
        return choice.value;
      }
      return param.defaultValue;
    case FractalParamType.boolean:
      return random.nextBool();
  }
}

/// Replayable decision for snapping a randomized float to slider precision.
///
/// Parameter schemas are hand-authored across a large catalog. A malformed
/// non-finite step or raw value must not crash randomization before the shared
/// schema normalizer gets a chance to clamp/fallback the value.
final class FractalParamStepSnapPlan {
  final double inputValue;
  final double step;
  final double value;
  final bool appliedStep;

  const FractalParamStepSnapPlan._({
    required this.inputValue,
    required this.step,
    required this.value,
    required this.appliedStep,
  });

  factory FractalParamStepSnapPlan.fromValue({
    required double value,
    required double step,
  }) {
    if (!value.isFinite || !step.isFinite || step <= 0.0) {
      return FractalParamStepSnapPlan._(
        inputValue: value,
        step: step,
        value: value,
        appliedStep: false,
      );
    }

    final snapped = (value / step).round() * step;
    if (!snapped.isFinite) {
      return FractalParamStepSnapPlan._(
        inputValue: value,
        step: step,
        value: value,
        appliedStep: false,
      );
    }

    return FractalParamStepSnapPlan._(
      inputValue: value,
      step: step,
      value: double.parse(snapped.toStringAsFixed(6)),
      appliedStep: true,
    );
  }
}

/// Snaps float randomization to slider step precision while avoiding typical
/// binary floating-point display noise.
double roundFractalParamValueToStep(double value, double step) {
  return FractalParamStepSnapPlan.fromValue(value: value, step: step).value;
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';

/// Numeric bounds derived from a [FractalParameter] schema.
///
/// Integer schemas store bounds as doubles because they share the numeric
/// parameter contract with float sliders. [containsInteger] exposes the hidden
/// assumption that those double bounds still include at least one valid integer
/// value before integer rounding is applied.
final class FractalNumericParamBounds {
  const FractalNumericParamBounds({
    required this.min,
    required this.max,
  });

  factory FractalNumericParamBounds.fromSchema(FractalParameter schema) {
    return FractalNumericParamBounds(min: schema.min, max: schema.max);
  }

  final double min;
  final double max;

  bool get hasFiniteOrderedRange => min.isFinite && max.isFinite && min <= max;

  bool get containsInteger =>
      hasFiniteOrderedRange && min.ceil() <= max.floor();

  double? tryNormalizeFloat(double value) {
    if (!hasFiniteOrderedRange) return null;
    return value.clamp(min, max).toDouble();
  }

  int? tryNormalizeInteger(double value) {
    if (!containsInteger) return null;
    final rounded = tryNormalizeFloat(value)!.round();
    return rounded.clamp(min.ceil(), max.floor()).toInt();
  }

  double normalizeFloat(double value) {
    assert(
      hasFiniteOrderedRange,
      'numeric parameter bounds must be finite and ordered',
    );
    return tryNormalizeFloat(value) ?? value;
  }

  int normalizeInteger(double value) {
    assert(
      containsInteger,
      'integer parameter bounds must include at least one integer value',
    );
    return tryNormalizeInteger(value) ?? value.round();
  }
}

/// Normalizes raw parameter values against a module parameter schema.
///
/// This keeps replayed state, presets, and direct UI updates on the same
/// contract: finite numeric values clamp to schema bounds after type coercion,
/// enum values must be one of the declared options, booleans must be real
/// booleans, and non-finite numeric values fall back to the schema default
/// instead of being promoted to an arbitrary bound.
Object normalizeFractalParamValue(FractalParameter schema, Object value) {
  if (schema.type == FractalParamType.boolean) {
    return value is bool ? value : _booleanDefault(schema);
  }
  if (schema.type == FractalParamType.enumeration) {
    final optionValues = schema.options.map((option) => option.value).toSet();
    return optionValues.contains(value) ? value : schema.defaultValue;
  }

  final numericValue = _finiteNumericValue(value);
  if (numericValue != null) {
    final bounds = FractalNumericParamBounds.fromSchema(schema);
    if (schema.type == FractalParamType.integer) {
      return bounds.tryNormalizeInteger(numericValue) ?? schema.defaultValue;
    }
    return bounds.tryNormalizeFloat(numericValue) ?? schema.defaultValue;
  }
  return schema.defaultValue;
}

double? _finiteNumericValue(Object value) {
  if (value is! num) return null;
  final numericValue = value.toDouble();
  return numericValue.isFinite ? numericValue : null;
}

bool _booleanDefault(FractalParameter schema) {
  final defaultValue = schema.defaultValue;
  return defaultValue is bool ? defaultValue : false;
}

import 'dart:math';

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_randomizer.dart';
import 'package:flutter_test/flutter_test.dart';

String _label(_) => 'Parameter';

FractalParameter _numericParam({
  required FractalParamType type,
  required Object defaultValue,
  double min = 1.2,
  double max = 10.8,
}) {
  return FractalParameter(
    id: 'value',
    label: _label,
    type: type,
    min: min,
    max: max,
    step: 1,
    defaultValue: defaultValue,
  );
}

final class _FixedRandom implements Random {
  _FixedRandom({
    required this.nextIntValue,
    this.nextDoubleValue = 0.0,
  });

  final int Function(int max) nextIntValue;
  final double nextDoubleValue;

  @override
  int nextInt(int max) => nextIntValue(max);

  @override
  double nextDouble() => nextDoubleValue;

  @override
  bool nextBool() => false;
}

void main() {
  group('FractalParamStepSnapPlan', () {
    test('exposes whether slider-step snapping was applied', () {
      final snapped = FractalParamStepSnapPlan.fromValue(
        value: 1.234567,
        step: 0.1,
      );
      final unsnapped = FractalParamStepSnapPlan.fromValue(
        value: 1.234567,
        step: double.nan,
      );

      expect(snapped.value, 1.2);
      expect(snapped.appliedStep, isTrue);
      expect(unsnapped.value, 1.234567);
      expect(unsnapped.appliedStep, isFalse);
    });
  });

  group('roundFractalParamValueToStep', () {
    test('ignores non-finite steps instead of throwing during randomization',
        () {
      expect(roundFractalParamValueToStep(1.234567, double.nan), 1.234567);
      expect(roundFractalParamValueToStep(1.234567, double.infinity), 1.234567);
    });

    test('keeps non-finite values replayable for later schema normalization',
        () {
      expect(roundFractalParamValueToStep(double.nan, 0.1), isNaN);
      expect(
          roundFractalParamValueToStep(double.infinity, 0.1), double.infinity);
    });
  });

  group('randomFractalParamValue', () {
    test('keeps integer random values inside fractional schema bounds', () {
      final schema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
      );

      expect(
        randomFractalParamValue(schema, _FixedRandom(nextIntValue: (_) => 0)),
        2,
      );
      expect(
        randomFractalParamValue(
          schema,
          _FixedRandom(nextIntValue: (max) => max - 1),
        ),
        10,
      );
    });

    test('normalizes stepped float random values back to schema bounds', () {
      final schema = _numericParam(
        type: FractalParamType.float,
        defaultValue: 4.0,
      );

      expect(
        randomFractalParamValue(schema, _FixedRandom(nextIntValue: (_) => 0)),
        1.2,
      );
      expect(
        randomFractalParamValue(
          schema,
          _FixedRandom(
            nextIntValue: (_) => 0,
            nextDoubleValue: 0.99,
          ),
        ),
        10.8,
      );
    });

    test('does not crash when a float schema has a non-finite step', () {
      final schema = FractalParameter(
        id: 'value',
        label: _label,
        type: FractalParamType.float,
        min: 1.2,
        max: 10.8,
        step: double.nan,
        defaultValue: 4.0,
      );

      expect(
        randomFractalParamValue(
          schema,
          _FixedRandom(
            nextIntValue: (_) => 0,
            nextDoubleValue: 0.5,
          ),
        ),
        closeTo(6.0, 1e-12),
      );
    });
  });
}

import 'package:flutter_fractals/core/models/fractal_parameter.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_param_value_normalizer.dart';
import 'package:flutter_test/flutter_test.dart';

String _label(_) => 'Parameter';

FractalParameter _booleanParam({required bool defaultValue}) {
  return FractalParameter(
    id: 'enabled',
    label: _label,
    type: FractalParamType.boolean,
    min: 0,
    max: 1,
    step: 1,
    defaultValue: defaultValue,
  );
}

FractalParameter _numericParam({
  required FractalParamType type,
  required Object defaultValue,
  double min = 1,
  double max = 10,
}) {
  return FractalParameter(
    id: 'value',
    label: _label,
    type: type,
    min: min,
    max: max,
    step: 1,
    defaultValue: defaultValue,
  );
}

void main() {
  group('normalizeFractalParamValue', () {
    test('preserves real boolean parameter values', () {
      final schema = _booleanParam(defaultValue: true);

      expect(normalizeFractalParamValue(schema, true), isTrue);
      expect(normalizeFractalParamValue(schema, false), isFalse);
    });

    test('falls back to boolean schema default for non-boolean values', () {
      expect(
        normalizeFractalParamValue(_booleanParam(defaultValue: true), 'true'),
        isTrue,
      );
      expect(
        normalizeFractalParamValue(_booleanParam(defaultValue: false), 1),
        isFalse,
      );
    });

    test('falls back to numeric schema default for non-finite numbers', () {
      final floatSchema = _numericParam(
        type: FractalParamType.float,
        defaultValue: 4.0,
      );
      final intSchema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
      );

      for (final candidate in [
        double.nan,
        double.infinity,
        double.negativeInfinity,
      ]) {
        expect(
          normalizeFractalParamValue(floatSchema, candidate),
          4.0,
          reason: 'float candidate=$candidate',
        );
        expect(
          normalizeFractalParamValue(intSchema, candidate),
          4,
          reason: 'integer candidate=$candidate',
        );
      }
    });

    test('falls back when numeric schema bounds cannot clamp safely', () {
      final reversedRange = _numericParam(
        type: FractalParamType.float,
        defaultValue: 4.0,
        min: 10,
        max: 1,
      );
      final nonFiniteRange = _numericParam(
        type: FractalParamType.float,
        defaultValue: 5.0,
        min: double.nan,
        max: 10,
      );

      expect(normalizeFractalParamValue(reversedRange, 6.0), 4.0);
      expect(normalizeFractalParamValue(nonFiniteRange, 6.0), 5.0);
    });

    test('falls back when integer schema bounds contain no integer value', () {
      final schema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
        min: 1.2,
        max: 1.8,
      );
      final bounds = FractalNumericParamBounds.fromSchema(schema);

      expect(bounds.hasFiniteOrderedRange, isTrue);
      expect(bounds.containsInteger, isFalse);
      expect(normalizeFractalParamValue(schema, 1.6), 4);
    });

    test('keeps rounded integer values inside fractional schema bounds', () {
      final schema = _numericParam(
        type: FractalParamType.integer,
        defaultValue: 4,
        min: 1.2,
        max: 10.8,
      );
      final bounds = FractalNumericParamBounds.fromSchema(schema);

      expect(bounds.containsInteger, isTrue);
      expect(normalizeFractalParamValue(schema, 1.2), 2);
      expect(normalizeFractalParamValue(schema, 10.8), 10);
    });
  });
}

import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';

const bool kForceCpuFallback =
    bool.fromEnvironment('FORCE_CPU_FALLBACK', defaultValue: false);
// Android emulator GPU is allowed in auto mode. Runtime health probes in
// FractalViewerScreen enforce fast fallback to CPU on invalid output.

enum RendererBackend { gpu, cpu }

enum FallbackReasonCode {
  none,
  forcedByFlag,
  androidEmulator,
  gpuHealthCheckFailed,
  deepZoomPrecision,
  manualToggle,
  moduleUnsupported,
}

class BackendDecision {
  final RendererBackend backend;
  final FallbackReasonCode reasonCode;
  final String detail;

  const BackendDecision({
    required this.backend,
    required this.reasonCode,
    required this.detail,
  });

  bool get isFallback => backend == RendererBackend.cpu;

  String get reasonToken {
    switch (reasonCode) {
      case FallbackReasonCode.none:
        return 'none';
      case FallbackReasonCode.forcedByFlag:
        return 'forced_by_flag';
      case FallbackReasonCode.androidEmulator:
        return 'android_emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'gpu_health_check_failed';
      case FallbackReasonCode.deepZoomPrecision:
        return 'deep_zoom_precision';
      case FallbackReasonCode.manualToggle:
        return 'manual_toggle';
      case FallbackReasonCode.moduleUnsupported:
        return 'module_unsupported';
    }
  }

  String toLogLine({required String moduleId}) {
    return '[renderer] backend_decision backend=${backend.name} reason=$reasonToken module=$moduleId detail=$detail';
  }

  String toUserStatusText() {
    if (!isFallback) return 'Renderer: GPU';
    switch (reasonCode) {
      case FallbackReasonCode.androidEmulator:
        return 'Using stable renderer for this Android emulator';
      case FallbackReasonCode.gpuHealthCheckFailed:
        return 'GPU output unavailable, using stable renderer';
      case FallbackReasonCode.deepZoomPrecision:
        return 'Deep zoom precision mode enabled';
      case FallbackReasonCode.manualToggle:
        return 'Renderer preference applied';
      case FallbackReasonCode.moduleUnsupported:
        return 'Stable renderer enabled for this fractal mode';
      case FallbackReasonCode.forcedByFlag:
        return 'Stable renderer forced by launch flag';
      case FallbackReasonCode.none:
        return 'Renderer: CPU';
    }
  }
}

class BackendPolicyInput {
  final bool isAndroid;
  final bool isWeb;
  final bool isEmulator;
  final RendererBackendMode userMode;
  final bool gpuHealthFailed;
  final bool deepZoomNeedsCpu;
  final FractalDimension dimension;

  const BackendPolicyInput({
    required this.isAndroid,
    required this.isWeb,
    required this.isEmulator,
    required this.userMode,
    required this.gpuHealthFailed,
    required this.deepZoomNeedsCpu,
    required this.dimension,
  });
}

/// Replayable explanation for the backend rule selected by the policy.
///
/// Platform probes are currently advisory in auto mode: Android emulator status
/// is logged and passed through, but runtime health checks decide fallback.
/// Keeping the selected rule visible makes that precedence testable instead of
/// hiding it in early returns.
class BackendPolicyResolution {
  final BackendDecision decision;
  final String selectedRule;
  final bool platformSignalsUsed;

  const BackendPolicyResolution({
    required this.decision,
    required this.selectedRule,
    required this.platformSignalsUsed,
  });
}

class RendererBackendPolicy {
  const RendererBackendPolicy();

  BackendDecision decide(BackendPolicyInput input) => explain(input).decision;

  BackendPolicyResolution explain(BackendPolicyInput input) {
    if (kForceCpuFallback) {
      return const BackendPolicyResolution(
        selectedRule: 'force_cpu_flag',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.forcedByFlag,
          detail: 'FORCE_CPU_FALLBACK=true',
        ),
      );
    }

    if (input.dimension != FractalDimension.twoD) {
      // 3D modules (e.g. Mandelbulb/Mandelbox) currently rely on GPU shader
      // rendering. Forcing CPU here only produces a disabled placeholder pane.
      // Keep these modules on GPU by default.
      if (input.userMode == RendererBackendMode.cpuOnly) {
        return const BackendPolicyResolution(
          selectedRule: 'gpu_required_module_cpu_only_ignored',
          platformSignalsUsed: false,
          decision: BackendDecision(
            backend: RendererBackend.gpu,
            reasonCode: FallbackReasonCode.moduleUnsupported,
            detail: 'cpu_only_ignored_for_3d_gpu_required',
          ),
        );
      }
      return const BackendPolicyResolution(
        selectedRule: 'gpu_required_module',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.none,
          detail: '3d_gpu_path',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.cpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_cpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'cpu_only',
        ),
      );
    }

    if (input.userMode == RendererBackendMode.gpuOnly) {
      return const BackendPolicyResolution(
        selectedRule: 'manual_gpu_only',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.gpu,
          reasonCode: FallbackReasonCode.manualToggle,
          detail: 'gpu_only',
        ),
      );
    }

    // Emulator targets are handled like physical devices in auto mode.
    // Runtime GPU health checks own fallback decisions.

    if (input.gpuHealthFailed) {
      return const BackendPolicyResolution(
        selectedRule: 'gpu_health_failed',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.gpuHealthCheckFailed,
          detail: 'frame_probe_detected_invalid_gpu_output',
        ),
      );
    }

    if (input.deepZoomNeedsCpu) {
      return const BackendPolicyResolution(
        selectedRule: 'deep_zoom_precision',
        platformSignalsUsed: false,
        decision: BackendDecision(
          backend: RendererBackend.cpu,
          reasonCode: FallbackReasonCode.deepZoomPrecision,
          detail: 'deep_zoom_precision_policy',
        ),
      );
    }

    return const BackendPolicyResolution(
      selectedRule: 'healthy_gpu_target',
      platformSignalsUsed: false,
      decision: BackendDecision(
        backend: RendererBackend.gpu,
        reasonCode: FallbackReasonCode.none,
        detail: 'healthy_gpu_target',
      ),
    );
  }
}

/// Replayable Android emulator signal snapshot.
///
/// Device probing is intentionally best-effort and IO-heavy; keeping the
/// signal classifier pure makes marker drift testable without touching
/// `/proc`, `getprop`, or `/system` in unit tests.
class AndroidEmulatorSignals {
  final String cpuInfo;
  final String hardware;
  final String buildCharacteristics;
  final String productModel;
  final String buildProp;

  const AndroidEmulatorSignals({
    this.cpuInfo = '',
    this.hardware = '',
    this.buildCharacteristics = '',
    this.productModel = '',
    this.buildProp = '',
  });

  bool get isEmulator =>
      AndroidEmulatorMarkerCatalog.hasCpuInfoMarker(cpuInfo) ||
      AndroidEmulatorMarkerCatalog.hasHardwareMarker(hardware) ||
      AndroidEmulatorMarkerCatalog.hasBuildCharacteristicsMarker(
        buildCharacteristics,
      ) ||
      AndroidEmulatorMarkerCatalog.hasProductModelMarker(productModel) ||
      AndroidEmulatorMarkerCatalog.hasBuildPropMarker(buildProp);
}

/// Named emulator marker contract used by Android emulator signal detection.
///
/// The markers are intentionally conservative: substring checks are used only
/// for fields that can contain labels or full property files, while the direct
/// `ro.hardware` value must match a known virtual hardware token exactly.
class AndroidEmulatorMarkerCatalog {
  static const List<String> cpuInfoSubstrings = [
    'ranchu',
    'goldfish',
    'qemu',
    'android virtual processor',
  ];
  static const List<String> exactHardwareValues = ['ranchu', 'goldfish'];
  static const List<String> buildCharacteristicsSubstrings = ['emulator'];
  static const List<String> productModelSubstrings = [
    'sdk_gphone',
    'android sdk built for',
  ];
  static const List<String> buildPropSubstrings = [
    'ro.hardware=goldfish',
    'ro.hardware=ranchu',
    'sdk_gphone',
    'generic_x86',
  ];

  const AndroidEmulatorMarkerCatalog._();

  static bool hasCpuInfoMarker(String value) {
    return _containsAny(value, cpuInfoSubstrings);
  }

  static bool hasHardwareMarker(String value) {
    return exactHardwareValues.contains(value.trim().toLowerCase());
  }

  static bool hasBuildCharacteristicsMarker(String value) {
    return _containsAny(value, buildCharacteristicsSubstrings);
  }

  static bool hasProductModelMarker(String value) {
    return _containsAny(value, productModelSubstrings);
  }

  static bool hasBuildPropMarker(String value) {
    return _containsAny(value, buildPropSubstrings);
  }

  static bool _containsAny(String value, List<String> markers) {
    final normalized = value.toLowerCase();
    return markers.any(normalized.contains);
  }
}

Future<bool> detectAndroidEmulator() async {
  if (kIsWeb || !Platform.isAndroid) return false;

  var signals = const AndroidEmulatorSignals();

  // 1. /proc/cpuinfo — check for emulator markers
  try {
    signals = AndroidEmulatorSignals(
      cpuInfo: await File('/proc/cpuinfo').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 2. getprop — most reliable on modern emulators
  try {
    final result = await Process.run('getprop', ['ro.hardware']);
    signals = AndroidEmulatorSignals(hardware: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.build.characteristics']);
    signals = AndroidEmulatorSignals(
      buildCharacteristics: result.stdout as String,
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  try {
    final result = await Process.run('getprop', ['ro.product.model']);
    signals = AndroidEmulatorSignals(productModel: result.stdout as String);
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  // 3. /system/build.prop — fallback file check
  try {
    signals = AndroidEmulatorSignals(
      buildProp: await File('/system/build.prop').readAsString(),
    );
    if (signals.isEmulator) return true;
  } catch (e) {
    if (kDebugMode) debugPrint('[FF] silent catch: $e');
  }

  return false;
}

import 'dart:typed_data';

import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/services/renderer_settings_service.dart';
