      expect(completion.progress, 1.0);
      expect(completion.status, 'Done');
    });

    test('reports cancelled runs with bounded partial progress', () {
      const completion = BatchExportCompletion(
        completedItems: 1,
        plannedItems: 3,
        wasCancelled: true,
      );
      const overrunCompletion = BatchExportCompletion(
        completedItems: 4,
        plannedItems: 3,
