import 'dart:async';
import 'dart:convert';
import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:path_provider/path_provider.dart';

/// Lightweight, local-only crash/error reporting with persistence.
///
/// Goals:
/// - Surface unexpected errors with consistent console tags.
/// - Keep an in-memory ring buffer that can be shared/exported.
/// - Optionally persist crash logs to disk for post-mortem analysis.
/// - Avoid collecting PII by not logging widget trees, user content, or
///   arbitrary metadata.
///
/// Features:
/// - Thread-safe event recording
/// - Automatic disk persistence (optional)
/// - Structured error categorization
/// - Export to JSON for bug reports
/// - Session tracking
///
/// This is intentionally *not* a remote crash analytics SDK.
class CrashReporter {
  CrashReporter._({
    int maxEvents = 100,
    bool persistToDisk = false,
  })  : _maxEvents = maxEvents,
        _persistToDisk = persistToDisk {
    _sessionId = _generateSessionId();
    _sessionStart = DateTime.now().toUtc();
    if (_persistToDisk) {
      _initDiskPersistence();
    }
  }

  static CrashReporter? _instance;

  /// Returns the singleton instance.
  ///
  /// Throws if [install] has not been called.
  static CrashReporter get instance {
    if (_instance == null) {
      throw StateError(
        'CrashReporter not initialized. Call CrashReporter.install() first.',
      );
    }
    return _instance!;
  }

  /// Returns the singleton instance, or null if not initialized.
  static CrashReporter? get instanceOrNull => _instance;

  final int _maxEvents;
  final bool _persistToDisk;
  final List<CrashEvent> _events = <CrashEvent>[];
  final Map<String, int> _errorCounts = {};
  late final String _sessionId;
  late final DateTime _sessionStart;
  File? _logFile;
  bool _diskInitialized = false;
  final StreamController<CrashEvent> _eventController =
      StreamController<CrashEvent>.broadcast();

  /// Stream of crash events for real-time monitoring.
  Stream<CrashEvent> get eventStream => _eventController.stream;

  /// Current session ID.
  String get sessionId => _sessionId;

  /// When this session started.
  DateTime get sessionStart => _sessionStart;

  /// Number of errors recorded this session.
  int get errorCount => _events.length;

  /// Number of fatal errors this session.
  int get fatalCount => _events.where((e) => e.fatal).length;

  /// Error counts by source category.
  Map<String, int> get errorCountsBySource => Map.unmodifiable(_errorCounts);

  /// Installs handlers for:
  /// - Flutter framework errors: [FlutterError.onError]
  /// - Platform dispatcher errors: [PlatformDispatcher.instance.onError]
  ///
  /// For uncaught async/zone errors use [runZonedGuarded] in `main()`.
  ///
  /// Options:
  /// - [maxEvents]: Maximum events to keep in memory (default: 100)
  /// - [persistToDisk]: Whether to save logs to disk (default: false)
  static void install({
    int maxEvents = 100,
    bool persistToDisk = false,
  }) {
    // Make install idempotent.
    _instance ??= CrashReporter._(
      maxEvents: maxEvents,
      persistToDisk: persistToDisk,
    );

    FlutterError.onError = (FlutterErrorDetails details) {
      // Keep Flutter's default formatting/behavior in debug.
      FlutterError.presentError(details);

      final Object exception = details.exception;
      final StackTrace? stack = details.stack;

      // Determine error source from context
      String source = 'flutter';
      if (details.library != null) {
        source = _categorizeFlutterError(details);
      }

      CrashReporter.instance.record(
        exception,
        stack,
        source: source,
        fatal: false,
        context: details.context?.toString(),
      );
    };

    // Catches errors that would otherwise be considered unhandled by the engine.
    PlatformDispatcher.instance.onError = (Object error, StackTrace stack) {
      CrashReporter.instance.record(
        error,
        stack,
        source: 'platform_dispatcher',
        fatal: true,
      );
      // Returning true tells the dispatcher we've handled it.
      return true;
    };
  }

  /// Categorizes Flutter errors by their library/context.
  static String _categorizeFlutterError(FlutterErrorDetails details) {
    final library = details.library ?? '';
    final context = details.context?.toString() ?? '';

    if (library.contains('rendering')) {
      return 'flutter_rendering';
    }
    if (library.contains('widgets')) {
      return 'flutter_widgets';
    }
    if (library.contains('gesture')) {
      return 'flutter_gesture';
    }
    if (library.contains('image') || context.contains('image')) {
      return 'flutter_image';
    }
    if (library.contains('shader') || context.contains('shader')) {
      return 'shader';
    }
    return 'flutter';
  }

  /// Records an error locally.
  ///
  /// Do not pass user-provided strings or large objects here.
  void record(
    Object error,
    StackTrace? stack, {
    required String source,
    required bool fatal,
    String? context,
    Map<String, String>? tags,
  }) {
    final event = CrashEvent(
      timestamp: DateTime.now().toUtc(),
      sessionId: _sessionId,
      source: source,
      fatal: fatal,
      error: _sanitizeError(error),
      errorType: error.runtimeType.toString(),
      stack: _sanitizeStack(stack),
      context: context,
      tags: tags ?? const {},
    );

    _events.add(event);
    if (_events.length > _maxEvents) {
      _events.removeRange(0, _events.length - _maxEvents);
    }

    // Track counts by source
    _errorCounts[source] = (_errorCounts[source] ?? 0) + 1;

    // Broadcast to listeners
    _eventController.add(event);

    // Log to console
    _printEvent(event);

    // Persist to disk if enabled
    if (_persistToDisk && _diskInitialized) {
      _persistEvent(event);
    }
  }

  /// Records an informational breadcrumb (not an error).
  ///
  /// Breadcrumbs provide context for debugging but aren't errors themselves.
  void addBreadcrumb(String message, {String category = 'navigation'}) {
    record(
      BreadcrumbMarker(message),
      null,
      source: 'breadcrumb_$category',
      fatal: false,
    );
  }

  /// Returns recent crash/error events (oldest -> newest).
  List<CrashEvent> get recentEvents => List.unmodifiable(_events);

  /// Returns events matching the given filter.
  List<CrashEvent> getEventsBySource(String source) {
    return _events.where((e) => e.source == source).toList();
  }

  /// Returns only fatal events.
  List<CrashEvent> get fatalEvents => _events.where((e) => e.fatal).toList();

  /// Builds an exportable text blob for bug reports.
  ///
  /// Keep it local. Let users explicitly choose where to share it.
  String exportRecentLogs({int? maxLines}) {
    final buffer = StringBuffer();
    buffer.writeln('=== Fractal Forge Crash Report ===');
    buffer.writeln('Session: $_sessionId');
    buffer.writeln('Started: ${_sessionStart.toIso8601String()}');
    buffer.writeln('Errors: ${_events.length} ($fatalCount fatal)');
    buffer.writeln('');

    final events = maxLines != null && _events.length > maxLines
        ? _events.sublist(_events.length - maxLines)
        : _events;

    for (final event in events) {
      buffer.writeln(event.toMultilineString());
    }

    return buffer.toString();
  }

  /// Exports all events as a JSON string.
  String exportAsJson() {
    final data = {
      'session_id': _sessionId,
      'session_start': _sessionStart.toIso8601String(),
      'export_time': DateTime.now().toUtc().toIso8601String(),
      'error_counts': _errorCounts,
      'events': _events.map((e) => e.toJson()).toList(),
    };
    return const JsonEncoder.withIndent('  ').convert(data);
  }

  /// Clears all recorded events.
  void clear() {
    _events.clear();
    _errorCounts.clear();
  }

  /// Disposes resources.
  void dispose() {
    _eventController.close();
  }

  Future<void> _initDiskPersistence() async {
    if (kIsWeb) return;
    try {
      final dir = await getApplicationDocumentsDirectory();
      final logsDir = Directory('${dir.path}/crash_logs');
      if (!await logsDir.exists()) {
        await logsDir.create(recursive: true);
      }

      // Clean up old log files (keep last 5)
      final files = await logsDir.list().toList();
      final logFiles = files
          .whereType<File>()
          .where((f) => f.path.endsWith('.log'))
          .toList()
        ..sort((a, b) => b.path.compareTo(a.path));

      for (var i = 5; i < logFiles.length; i++) {
        await logFiles[i].delete();
      }

      final timestamp = DateTime.now()
          .toIso8601String()
          .replaceAll(':', '-')
          .substring(0, 19);
      _logFile = File('${logsDir.path}/crash_$timestamp.log');
      await _logFile!.writeAsString(
        '=== Session: $_sessionId ===\n',
        mode: FileMode.write,
      );
      _diskInitialized = true;
    } catch (e) {
      if (kDebugMode) debugPrint('[FF_CRASH][WARN] Failed to init disk persistence: $e');
    }
  }

  Future<void> _persistEvent(CrashEvent event) async {
    try {
      await _logFile?.writeAsString(
        '${event.toMultilineString()}\n',
        mode: FileMode.append,
      );
    } catch (e) {
      // Silently fail disk writes - we don't want to crash on crash handling
    }
  }

  void _printEvent(CrashEvent e) {
    // Skip breadcrumbs in release mode
    if (!kDebugMode && e.source.startsWith('breadcrumb_')) {
      return;
    }

    final level = e.fatal ? 'FATAL' : 'ERROR';
    if (kDebugMode) debugPrint('[FF_CRASH][$level][${e.source}] ${e.error}');
    if (kDebugMode) {
      if (e.context != null) {
        debugPrint('[FF_CRASH][CTX] ${e.context}');
      }
      if (e.stack != null && e.stack!.isNotEmpty) {
        debugPrint('[FF_CRASH][STACK] ${e.stack}');
      }
    }
  }

  String _sanitizeError(Object error) {
    // Handle special marker types
    if (error is BreadcrumbMarker) {
      return '[BREADCRUMB] ${error.message}';
    }

    var s = error.toString();
    s = _stripPotentialPaths(s);
    const maxLen = 800;
    if (s.length > maxLen) {
      s = '${s.substring(0, maxLen)}…(truncated)';
    }
    return s;
  }

  String? _sanitizeStack(StackTrace? stack) {
    if (stack == null) return null;
    var s = stack.toString();
    s = _stripPotentialPaths(s);

    // Keep stack traces short: enough to diagnose, not enough to be noisy.
    final lines = s.split('\n');
    final kept = lines.take(40).toList();
    s = kept.join('\n').trim();
    return s.isEmpty ? null : s;
  }

  String _stripPotentialPaths(String input) {
    var s = input;

    // file:///Users/<name>/... or file:///home/<name>/...
    s = s.replaceAllMapped(
      RegExp(r'file:///((Users|home)/)[^/\s]+'),
      (match) => 'file:///${match.group(1)!}…',
    );

    // /Users/<name>/... or /home/<name>/...
    s = s.replaceAllMapped(
      RegExp(r'/(Users|home)/[^/\s]+'),
      (match) => '/${match.group(1)!}/…',
    );

    // Android internal app data paths
    s = s.replaceAll(
      RegExp(r'/data/(data|user/\d+)/[^/\s]+'),
      '/data/.../',
    );

    return s;
  }

  String _generateSessionId() {
    final now = DateTime.now();
    final hash = now.millisecondsSinceEpoch.toRadixString(36);
    return 'FF${hash.toUpperCase()}';
  }
}

/// Marker class for breadcrumb events (not actual errors).
class BreadcrumbMarker {
  final String message;
  const BreadcrumbMarker(this.message);

  @override
  String toString() => message;
}

/// A single crash/error event with metadata.
class CrashEvent {
  final DateTime timestamp;
  final String sessionId;
  final String source;
  final bool fatal;
  final String error;
  final String errorType;
  final String? stack;
  final String? context;
  final Map<String, String> tags;

  CrashEvent({
    required this.timestamp,
    required this.sessionId,
    required this.source,
    required this.fatal,
    required this.error,
    required this.errorType,
    this.stack,
    this.context,
    Map<String, String> tags = const {},
  }) : tags = _CrashEventTags.snapshot(tags);

  /// Creates a CrashEvent from JSON data.
  factory CrashEvent.fromJson(Map<String, dynamic> json) {
    return CrashEvent(
      timestamp: DateTime.parse(json['timestamp'] as String),
      sessionId: json['session_id'] as String,
      source: json['source'] as String,
      fatal: json['fatal'] as bool,
      error: json['error'] as String,
      errorType: json['error_type'] as String,
      stack: json['stack'] as String?,
      context: json['context'] as String?,
      tags: Map<String, String>.from(json['tags'] as Map? ?? {}),
    );
  }

  /// Converts this event to a JSON map.
  Map<String, dynamic> toJson() {
    return {
      'timestamp': timestamp.toIso8601String(),
      'session_id': sessionId,
      'source': source,
      'fatal': fatal,
      'error': error,
      'error_type': errorType,
      if (stack != null) 'stack': stack,
      if (context != null) 'context': context,
      if (tags.isNotEmpty) 'tags': Map<String, String>.from(tags),
    };
  }

  String toSingleLineString() {
    final t = timestamp.toIso8601String();
    final level = fatal ? 'FATAL' : 'ERROR';
    return '[$t][$level][$source] $error';
  }

  String toMultilineString() {
    final buffer = StringBuffer();
    buffer.writeln(toSingleLineString());
    if (context != null) {
      buffer.writeln('  Context: $context');
    }
    if (tags.isNotEmpty) {
      buffer.writeln('  Tags: ${tags.entries.map((e) => '${e.key}=${e.value}').join(', ')}');
    }
    if (stack != null && stack!.isNotEmpty) {
      buffer.writeln('  Stack:\n${_indentStack(stack!)}');
    }
    return buffer.toString();
  }

  String _indentStack(String stack) {
    return stack.split('\n').map((line) => '    $line').join('\n');
  }

  @override
  String toString() => toSingleLineString();
}

/// Snapshot boundary for event tag provenance.
///
/// Crash events can outlive mutable caller-owned maps. Copying and freezing
/// tags when the event is created keeps exported logs replayable even if the
/// caller later reuses or mutates its tag map.
final class _CrashEventTags {
  const _CrashEventTags._();

  static Map<String, String> snapshot(Map<String, String> tags) {
    if (tags.isEmpty) return const {};
    return Map<String, String>.unmodifiable(tags);
  }
}

/// Extension for adding error recording to async operations.
extension CrashReporterExtension on Future {
  /// Wraps this future with crash reporting on error.
  Future<T> withCrashReporting<T>(String source) {
    return then<T>((value) => value as T).catchError((Object error, StackTrace stack) {
      CrashReporter.instance.record(
        error,
        stack,
        source: source,
        fatal: false,
      );
      throw error;
    });
  }
}

/// Mixin for widgets that need crash reporting context.
mixin CrashReporterMixin {
  /// Records an error from this widget.
  void recordError(
    Object error,
    StackTrace? stack, {
    required String source,
    bool fatal = false,
    String? context,
  }) {
    CrashReporter.instance.record(
      error,
      stack,
      source: source,
      fatal: fatal,
      context: context,
    );
  }

  /// Adds a navigation breadcrumb.
  void addNavigationBreadcrumb(String routeName) {
    CrashReporter.instance.addBreadcrumb(
      'Navigated to $routeName',
      category: 'navigation',
    );
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/services/crash_reporter.dart';

void main() {
  group('CrashReporter', () {
    setUpAll(() {
      // Initialize crash reporter
      CrashReporter.install(maxEvents: 50, persistToDisk: false);
    });

    setUp(() {
      // Clear events before each test
      CrashReporter.instance.clear();
    });

    test('instance is initialized after install', () {
      expect(CrashReporter.instance, isNotNull);
      expect(CrashReporter.instanceOrNull, isNotNull);
    });

    test('has session ID', () {
      expect(CrashReporter.instance.sessionId, isNotEmpty);
      expect(CrashReporter.instance.sessionId.startsWith('FF'), isTrue);
    });

    test('has session start time', () {
      final now = DateTime.now().toUtc();
      final sessionStart = CrashReporter.instance.sessionStart;

      expect(sessionStart.isBefore(now.add(const Duration(seconds: 1))), isTrue);
      expect(sessionStart.isAfter(now.subtract(const Duration(hours: 1))), isTrue);
    });

    test('records error events', () {
      CrashReporter.instance.record(
        Exception('Test error'),
        StackTrace.current,
        source: 'test',
        fatal: false,
      );

      expect(CrashReporter.instance.errorCount, equals(1));
      expect(CrashReporter.instance.recentEvents, hasLength(1));
    });

    test('records fatal events', () {
      CrashReporter.instance.record(
        Exception('Fatal error'),
        StackTrace.current,
        source: 'test',
        fatal: true,
      );

      expect(CrashReporter.instance.fatalCount, equals(1));
      expect(CrashReporter.instance.fatalEvents, hasLength(1));
    });

    test('records events with context', () {
      CrashReporter.instance.record(
        Exception('Error with context'),
        null,
        source: 'test',
        fatal: false,
        context: 'During shader compilation',
      );

      final event = CrashReporter.instance.recentEvents.first;
      expect(event.context, equals('During shader compilation'));
    });

    test('records events with tags', () {
      CrashReporter.instance.record(
        Exception('Tagged error'),
        null,
        source: 'test',
        fatal: false,
        tags: {'module': 'mandelbrot', 'attempt': '1'},
      );

      final event = CrashReporter.instance.recentEvents.first;
      expect(event.tags['module'], equals('mandelbrot'));
      expect(event.tags['attempt'], equals('1'));
    });

    test('records tags as immutable event snapshots', () {
      final tags = {'module': 'mandelbrot'};

      CrashReporter.instance.record(
        Exception('Tagged error'),
        null,
        source: 'test',
        fatal: false,
        tags: tags,
      );

      tags['module'] = 'julia';
      tags['attempt'] = '2';

      final event = CrashReporter.instance.recentEvents.single;
      expect(event.tags, equals({'module': 'mandelbrot'}));
      expect(
        () => event.tags['module'] = 'julia',
        throwsUnsupportedError,
      );
    });

    test('tracks error counts by source', () {
      CrashReporter.instance.record(
        Exception('Error 1'),
        null,
        source: 'shader',
        fatal: false,
      );
      CrashReporter.instance.record(
        Exception('Error 2'),
        null,
        source: 'shader',
        fatal: false,
      );
      CrashReporter.instance.record(
        Exception('Error 3'),
        null,
        source: 'network',
        fatal: false,
      );

      expect(CrashReporter.instance.errorCountsBySource['shader'], equals(2));
      expect(CrashReporter.instance.errorCountsBySource['network'], equals(1));
    });

    test('limits events to maxEvents', () {
      // Install with small limit for testing
      // Note: Can't reinstall, so we test with existing instance
      for (var i = 0; i < 100; i++) {
        CrashReporter.instance.record(
          Exception('Error $i'),
          null,
          source: 'test',
          fatal: false,
        );
      }

      // Should be capped at 50 (the maxEvents we set in setUpAll)
      expect(CrashReporter.instance.errorCount, equals(50));
    });

    test('clears events', () {
      CrashReporter.instance.record(
        Exception('Error'),
        null,
        source: 'test',
        fatal: false,
      );

      expect(CrashReporter.instance.errorCount, greaterThan(0));

      CrashReporter.instance.clear();

      expect(CrashReporter.instance.errorCount, equals(0));
      expect(CrashReporter.instance.errorCountsBySource, isEmpty);
    });

    test('filters events by source', () {
      CrashReporter.instance.record(
        Exception('Shader error'),
        null,
        source: 'shader',
        fatal: false,
      );
      CrashReporter.instance.record(
        Exception('Network error'),
        null,
        source: 'network',
        fatal: false,
      );

      final shaderEvents = CrashReporter.instance.getEventsBySource('shader');
      expect(shaderEvents, hasLength(1));
      expect(shaderEvents.first.source, equals('shader'));
    });

    test('adds breadcrumbs', () {
      CrashReporter.instance.addBreadcrumb(
        'User navigated to settings',
        category: 'navigation',
      );

      final events = CrashReporter.instance.recentEvents;
      expect(events.last.error, contains('BREADCRUMB'));
      expect(events.last.source, equals('breadcrumb_navigation'));
    });

    test('exports logs as text', () {
      CrashReporter.instance.record(
        Exception('Test export error'),
        null,
        source: 'test',
        fatal: false,
      );

      final logs = CrashReporter.instance.exportRecentLogs();

      expect(logs, contains('Fractal Forge Crash Report'));
      expect(logs, contains('Session:'));
      expect(logs, contains('Test export error'));
    });

    test('exports logs with line limit', () {
      for (var i = 0; i < 10; i++) {
        CrashReporter.instance.record(
          Exception('Error $i'),
          null,
          source: 'test',
          fatal: false,
        );
      }

      final logs = CrashReporter.instance.exportRecentLogs(maxLines: 3);
      // Should contain header plus last 3 events
      expect(logs, contains('Error 7'));
      expect(logs, contains('Error 8'));
      expect(logs, contains('Error 9'));
    });

    test('exports as JSON', () {
      CrashReporter.instance.record(
        Exception('JSON test error'),
        null,
        source: 'test',
        fatal: false,
      );

      final json = CrashReporter.instance.exportAsJson();

      expect(json, contains('"session_id"'));
      expect(json, contains('"events"'));
      expect(json, contains('JSON test error'));
    });

    test('event stream broadcasts events', () async {
      final events = <CrashEvent>[];
      final subscription = CrashReporter.instance.eventStream.listen((event) {
        events.add(event);
      });

      CrashReporter.instance.record(
        Exception('Stream test'),
        null,
        source: 'test',
        fatal: false,
      );

      // Wait for event to be broadcast
      await Future.delayed(const Duration(milliseconds: 10));

      expect(events, hasLength(1));
      expect(events.first.error, contains('Stream test'));

      await subscription.cancel();
    });

    test('sanitizes file paths in errors', () {
      CrashReporter.instance.record(
        Exception('Error at /Users/testuser/project/file.dart'),
        null,
        source: 'test',
        fatal: false,
      );

      final event = CrashReporter.instance.recentEvents.first;
      expect(event.error, isNot(contains('testuser')));
    });

    test('sanitized paths do not expose regex replacement markers', () {
      CrashReporter.instance.record(
        Exception(
          'Error at file:///home/testuser/project/file.dart and '
          '/Users/testuser/project/file.dart',
        ),
        null,
        source: 'test',
        fatal: false,
      );

      final event = CrashReporter.instance.recentEvents.first;
      expect(event.error, isNot(contains('testuser')));
      expect(event.error, isNot(contains(r'$1')));
      expect(event.error, contains('file:///home/…'));
      expect(event.error, contains('/Users/…'));
    });

    test('truncates long error messages', () {
      final longMessage = 'x' * 1000;
      CrashReporter.instance.record(
        Exception(longMessage),
        null,
        source: 'test',
        fatal: false,
      );

      final event = CrashReporter.instance.recentEvents.first;
      expect(event.error.length, lessThan(850)); // 800 + some overhead
      expect(event.error, contains('truncated'));
    });
  });

  group('CrashEvent', () {
    test('creates from required parameters', () {
      final event = CrashEvent(
        timestamp: DateTime.utc(2024, 1, 15, 10, 30),
        sessionId: 'FF123',
        source: 'test',
        fatal: false,
        error: 'Test error',
        errorType: 'Exception',
      );

      expect(event.timestamp, equals(DateTime.utc(2024, 1, 15, 10, 30)));
      expect(event.sessionId, equals('FF123'));
      expect(event.source, equals('test'));
      expect(event.fatal, isFalse);
      expect(event.error, equals('Test error'));
      expect(event.errorType, equals('Exception'));
      expect(event.stack, isNull);
      expect(event.context, isNull);
      expect(event.tags, isEmpty);
    });

    test('converts to single line string', () {
      final event = CrashEvent(
        timestamp: DateTime.utc(2024, 1, 15, 10, 30),
        sessionId: 'FF123',
        source: 'shader',
        fatal: true,
        error: 'Shader compilation failed',
        errorType: 'ShaderException',
      );

      final line = event.toSingleLineString();

      expect(line, contains('[FATAL]'));
      expect(line, contains('[shader]'));
      expect(line, contains('Shader compilation failed'));
    });

    test('converts to multiline string', () {
      final event = CrashEvent(
        timestamp: DateTime.utc(2024, 1, 15, 10, 30),
        sessionId: 'FF123',
        source: 'test',
        fatal: false,
        error: 'Test error',
        errorType: 'Exception',
        context: 'During initialization',
        stack: 'line1\nline2',
        tags: {'key': 'value'},
      );

      final multiline = event.toMultilineString();

      expect(multiline, contains('Test error'));
      expect(multiline, contains('Context: During initialization'));
      expect(multiline, contains('Tags: key=value'));
      expect(multiline, contains('Stack:'));
    });

    test('converts to and from JSON', () {
      final original = CrashEvent(
        timestamp: DateTime.utc(2024, 1, 15, 10, 30),
        sessionId: 'FF123',
        source: 'test',
        fatal: true,
        error: 'Test error',
        errorType: 'Exception',
        context: 'Test context',
        stack: 'test stack',
        tags: {'key': 'value'},
      );

      final json = original.toJson();
      final restored = CrashEvent.fromJson(json);

      expect(restored.timestamp, equals(original.timestamp));
      expect(restored.sessionId, equals(original.sessionId));
      expect(restored.source, equals(original.source));
      expect(restored.fatal, equals(original.fatal));
      expect(restored.error, equals(original.error));
      expect(restored.errorType, equals(original.errorType));
      expect(restored.context, equals(original.context));
      expect(restored.stack, equals(original.stack));
      expect(restored.tags, equals(original.tags));
    });

    test('toString returns single line', () {
      final event = CrashEvent(
        timestamp: DateTime.utc(2024, 1, 15),
        sessionId: 'FF123',
        source: 'test',
        fatal: false,
        error: 'Error',
        errorType: 'Exception',
      );

      expect(event.toString(), equals(event.toSingleLineString()));
    });
  });

  group('BreadcrumbMarker', () {
    test('stores message', () {
      const marker = BreadcrumbMarker('Navigation event');
      expect(marker.message, equals('Navigation event'));
    });

    test('toString returns message', () {
      const marker = BreadcrumbMarker('Test breadcrumb');
      expect(marker.toString(), equals('Test breadcrumb'));
    });
  });

  group('CrashReporterExtension', () {
    test('withCrashReporting catches errors', () async {
      CrashReporter.instance.clear();

      try {
        await Future<void>.error(Exception('Async error'))
            .withCrashReporting<void>('async_test');
      } catch (_) {
        // Expected
      }

      expect(CrashReporter.instance.errorCount, equals(1));
      expect(
        CrashReporter.instance.recentEvents.first.source,
        equals('async_test'),
      );
    });

    test('withCrashReporting passes through successful results', () async {
      final result = await Future.value(42).withCrashReporting<int>('test');
      expect(result, equals(42));
    });
  });
}

import 'dart:collection';
import 'dart:convert';
import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:path_provider/path_provider.dart';

/// Severity levels for log entries.
enum LogLevel { debug, info, warn, error }

/// JSON-safe structured data attached to an in-memory log entry.
///
/// Logger callers often pass diagnostic objects that are useful in debug text
/// but are not directly JSON encodable (for example [DateTime], enum values,
/// non-finite doubles, or opaque objects). Snapshot at the record boundary so
/// debug log lines and exported JSON remain replayable even if callers mutate
/// their original metadata map later.
class _LogStructuredData {
  const _LogStructuredData._();

  static Map<String, Object?>? snapshot(Map<String, Object?>? data) {
    if (data == null) return null;
    return Map<String, Object?>.unmodifiable({
      for (final entry in data.entries) entry.key: snapshotValue(entry.value),
    });
  }

  static Object? snapshotValue(Object? value) {
    if (value == null || value is String || value is bool) return value;
    if (value is num) return value.isFinite ? value : value.toString();
    if (value is DateTime) return value.toIso8601String();
    if (value is Enum) return value.name;
    if (value is List) {
      return List<Object?>.unmodifiable(value.map(snapshotValue));
    }
    if (value is Map) {
      return Map<String, Object?>.unmodifiable({
        for (final entry in value.entries)
          entry.key.toString(): snapshotValue(entry.value),
      });
    }
    return value.toString();
  }
}

/// A single timestamped log entry.
class LogEntry {
  LogEntry({
    required this.timestamp,
    required this.level,
    required this.category,
    required this.message,
    Map<String, Object?>? data,
  }) : data = _LogStructuredData.snapshot(data);

  final DateTime timestamp;
  final LogLevel level;

  /// Short tag: 'action', 'render', 'gpu', 'state', 'lifecycle', 'export', etc.
  final String category;
  final String message;

  /// Optional structured data (e.g. fractal state snapshot).
  final Map<String, Object?>? data;

  Map<String, Object?> toJson() => {
        't': timestamp.toIso8601String(),
        'level': level.name,
        'cat': category,
        'msg': message,
        if (data != null) 'data': data,
      };

  /// Serialises to a JSONL line using the on-disk schema.
  Map<String, Object?> toDiskJson() => {
        'timestamp': timestamp.toIso8601String(),
        'level': level.name,
        'tag': category,
        'message': message,
      };

  /// Deserialises from the on-disk JSONL schema.
  factory LogEntry.fromDiskJson(Map<String, dynamic> json) {
    return LogEntry(
      timestamp: DateTime.parse(json['timestamp'] as String),
      level: LogLevel.values.firstWhere(
        (l) => l.name == (json['level'] as String),
        orElse: () => LogLevel.info,
      ),
      category: json['tag'] as String? ?? '',
      message: json['message'] as String? ?? '',
    );
  }

  String toLogLine() {
    final ts =
        '${timestamp.hour.toString().padLeft(2, '0')}:${timestamp.minute.toString().padLeft(2, '0')}:${timestamp.second.toString().padLeft(2, '0')}.${timestamp.millisecond.toString().padLeft(3, '0')}';
    final dataStr = data != null ? ' ${jsonEncode(data)}' : '';
    return '[$ts][${level.name}][$category] $message$dataStr';
  }
}

/// Replayable result of rotating an on-disk JSONL log file.
@immutable
class LogDiskRotationPlan {
  const LogDiskRotationPlan({
    required this.keptLines,
    required this.nonEmptyLineCount,
  });

  /// Non-empty JSONL lines kept in chronological order.
  final List<String> keptLines;

  /// Count of non-empty candidate lines before rotation.
  final int nonEmptyLineCount;

  bool get shouldRewrite => keptLines.length < nonEmptyLineCount;

  int get keptUtf8Bytes => keptLines.fold<int>(
        0,
        (total, line) => total + utf8.encode(line).length + 1,
      );

  String serializeKeptLines() => keptLines.map((line) => '$line\n').join();
}

/// Pure on-disk log rotation policy.
///
/// Keeps the most recent non-empty lines as one chronological suffix constrained
/// by entry count and byte budget. Exposing the selection makes dropped-line and
/// byte-budget assumptions testable without touching platform cache files.
class LogDiskRotationPolicy {
  const LogDiskRotationPolicy._();

  static LogDiskRotationPlan plan({
    required List<String> lines,
    required int maxEntries,
    required int maxBytes,
  }) {
    assert(maxEntries > 0, 'maxEntries must be positive');
    assert(maxBytes > 0, 'maxBytes must be positive');

    final nonEmptyLineCount =
        lines.where((line) => line.trim().isNotEmpty).length;
    final keptReversed = <String>[];
    var totalBytes = 0;

    for (final line in lines.reversed) {
      if (line.trim().isEmpty) continue;
      if (keptReversed.length >= maxEntries) break;
      final lineBytes = utf8.encode(line).length + 1; // +1 for newline
      if (totalBytes + lineBytes > maxBytes) break;
      totalBytes += lineBytes;
      keptReversed.add(line);
    }

    return LogDiskRotationPlan(
      keptLines: keptReversed.reversed.toList(growable: false),
      nonEmptyLineCount: nonEmptyLineCount,
    );
  }
}

/// Global in-memory ring-buffer logger with optional persistent JSONL storage.
///
/// Keeps the last [maxEntries] log entries in memory. Export as text or JSON
/// at any time via [exportText] / [exportJson].
///
/// Call [init] once at app startup to enable persistence:
/// ```dart
/// await AppLogger.instance.init();
/// ```
///
/// Usage:
/// ```dart
/// AppLogger.instance.log('action', 'User tapped zoom reset');
/// AppLogger.instance.logState('render', 'Backend switched', {'backend': 'cpu', 'reason': 'gpu_health'});
/// ```
class AppLogger extends ChangeNotifier {
  AppLogger._({this.maxEntries = 2000}); // ignore: unused_element_parameter

  static final AppLogger instance = AppLogger._();

  /// Maximum entries kept in the ring buffer.
  final int maxEntries;

  /// Maximum entries persisted to disk (rotation threshold).
  static const int _maxDiskEntries = 5000;

  /// Approximate size cap for the on-disk file (~2 MB).
  static const int _maxDiskBytes = 2 * 1024 * 1024;

  final Queue<LogEntry> _entries = Queue<LogEntry>();

  File? _logFile;
  IOSink? _sink;
  bool _persistenceReady = false;

  /// Read-only view of all entries (oldest first).
  List<LogEntry> get entries => _entries.toList(growable: false);

  int get length => _entries.length;

  // ── Initialisation ──────────────────────────────────────────────────

  /// Initialise persistent storage. Safe to call multiple times; subsequent
  /// calls are no-ops. Skipped automatically on web (no filesystem).
  Future<void> init() async {
    if (_persistenceReady) return;
    if (kIsWeb) return;

    try {
      final cacheDir = await getApplicationCacheDirectory();
      _logFile = File('${cacheDir.path}/fractal_forge_logs.jsonl');
      await _loadFromDisk();
      _sink = _logFile!.openWrite(mode: FileMode.append);
      _persistenceReady = true;
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[AppLogger] Failed to init persistence: $e');
      }
      // Graceful degradation: continue with in-memory only.
      _logFile = null;
      _sink = null;
    }
  }

  // ── Disk I/O ────────────────────────────────────────────────────────

  Future<void> _loadFromDisk() async {
    final file = _logFile;
    if (file == null || !file.existsSync()) return;

    try {
      final lines = await file.readAsLines();

      // Rotation: keep only the last _maxDiskEntries lines that fit within
      // _maxDiskBytes when re-encoded.
      final rotation = LogDiskRotationPolicy.plan(
        lines: lines,
        maxEntries: _maxDiskEntries,
        maxBytes: _maxDiskBytes,
      );

      // If we trimmed anything, rewrite the file to reclaim space.
      if (rotation.shouldRewrite) {
        await file.writeAsString(rotation.serializeKeptLines());
      }

      // Parse and load into ring buffer (in-memory max still applies).
      for (final line in rotation.keptLines) {
        try {
          final json = jsonDecode(line) as Map<String, dynamic>;
          final entry = LogEntry.fromDiskJson(json);
          _entries.addLast(entry);
          while (_entries.length > maxEntries) {
            _entries.removeFirst();
          }
        } catch (_) {
          // Skip malformed lines.
        }
      }
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[AppLogger] Failed to load log from disk: $e');
      }
    }
  }

  void _appendToDisk(LogEntry entry) {
    final sink = _sink;
    if (sink == null) return;

    try {
      sink.writeln(jsonEncode(entry.toDiskJson()));
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[AppLogger] Failed to write log entry to disk: $e');
      }
    }
  }

  // ── Logging methods ────────────────────────────────────────────────

  void log(String category, String message,
      {LogLevel level = LogLevel.info, Map<String, Object?>? data}) {
    final entry = LogEntry(
      timestamp: DateTime.now(),
      level: level,
      category: category,
      message: message,
      data: data,
    );
    _entries.addLast(entry);
    while (_entries.length > maxEntries) {
      _entries.removeFirst();
    }
    if (kDebugMode) {
      debugPrint(entry.toLogLine());
    }
    _appendToDisk(entry);
    notifyListeners();
  }

  /// Convenience: log with structured data.
  void logState(String category, String message, Map<String, Object?> data,
      {LogLevel level = LogLevel.info}) {
    log(category, message, level: level, data: data);
  }

  void debug(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.debug, data: data);

  void info(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.info, data: data);

  void warn(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.warn, data: data);

  void error(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.error, data: data);

  // ── Export ──────────────────────────────────────────────────────────

  /// Plain-text export (one line per entry).
  String exportText({LogLevel? minLevel}) {
    final filtered = minLevel == null
        ? _entries
        : _entries.where((e) => e.level.index >= minLevel.index);
    return filtered.map((e) => e.toLogLine()).join('\n');
  }

  /// JSON array export.
  String exportJson({LogLevel? minLevel, bool pretty = true}) {
    final filtered = minLevel == null
        ? _entries
        : _entries.where((e) => e.level.index >= minLevel.index);
    final list = filtered.map((e) => e.toJson()).toList();
    return pretty
        ? const JsonEncoder.withIndent('  ').convert(list)
        : jsonEncode(list);
  }

  // ── Clear ────────────────────────────────────────────────────────────

  /// Clear all entries from memory and truncate the on-disk file.
  Future<void> clearLog() async {
    _entries.clear();
    await _truncateDisk();
    notifyListeners();
  }

  /// Synchronous clear (in-memory only; schedules disk truncation).
  void clear() {
    _entries.clear();
    _truncateDisk(); // fire-and-forget
    notifyListeners();
  }

  Future<void> _truncateDisk() async {
    final file = _logFile;
    if (file == null || !_persistenceReady) return;

    try {
      // Close the current sink, truncate the file, reopen for append.
      await _sink?.flush();
      await _sink?.close();
      _sink = null;
      await file.writeAsString('');
      _sink = file.openWrite(mode: FileMode.append);
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[AppLogger] Failed to truncate log file: $e');
      }
    }
  }

  // ── Dispose ──────────────────────────────────────────────────────────

  @override
  Future<void> dispose() async {
    try {
      await _sink?.flush();
      await _sink?.close();
    } catch (_) {}
    _sink = null;
    super.dispose();
  }
}

import 'dart:convert';
import 'dart:io';

import 'package:flutter_fractals/core/services/app_logger_service.dart';
import 'package:flutter_test/flutter_test.dart';

final class _OpaqueLogValue {
  const _OpaqueLogValue();

  @override
  String toString() => 'opaque-log-value';
}

void main() {
  // Use a fresh AppLogger per test so ring-buffer state does not bleed.
  late AppLogger logger;

  setUp(() async {
    // Clear the singleton's ring buffer before each test.
    await AppLogger.instance.clearLog();
    logger = AppLogger.instance;
  });

  group('AppLogger — ring buffer', () {
    test('log adds entry to ring buffer', () {
      expect(logger.length, 0);
      logger.log('render', 'frame rendered');
      expect(logger.length, 1);
      expect(logger.entries.first.message, 'frame rendered');
      expect(logger.entries.first.category, 'render');
    });

    test('log trims to maxEntries when exceeded', () {
      // maxEntries defaults to 2000; use reflection-free approach: add
      // maxEntries+1 items and verify oldest is removed.
      final max = logger.maxEntries;
      for (int i = 0; i <= max; i++) {
        logger.log('cat', 'msg$i');
      }
      expect(logger.length, max);
      // First entry should be msg1 (msg0 was trimmed)
      expect(logger.entries.first.message, 'msg1');
      expect(logger.entries.last.message, 'msg$max');
    });

    test('entries returns oldest-first list', () {
      logger.log('a', 'first');
      logger.log('b', 'second');
      logger.log('c', 'third');

      final entries = logger.entries;
      expect(entries[0].message, 'first');
      expect(entries[1].message, 'second');
      expect(entries[2].message, 'third');
    });
  });

  group('AppLogger — convenience level methods', () {
    test('debug sets level to debug', () {
      logger.debug('cat', 'dbg msg');
      expect(logger.entries.last.level, LogLevel.debug);
    });

    test('info sets level to info', () {
      logger.info('cat', 'info msg');
      expect(logger.entries.last.level, LogLevel.info);
    });

    test('warn sets level to warn', () {
      logger.warn('cat', 'warn msg');
      expect(logger.entries.last.level, LogLevel.warn);
    });

    test('error sets level to error', () {
      logger.error('cat', 'error msg');
      expect(logger.entries.last.level, LogLevel.error);
    });

    test('log default level is info', () {
      logger.log('cat', 'default level');
      expect(logger.entries.last.level, LogLevel.info);
    });
  });

  group('AppLogger — exportText', () {
    test('exportText returns all entries as lines', () {
      logger.log('a', 'line one');
      logger.log('b', 'line two');
      logger.log('c', 'line three');

      final text = logger.exportText();
      final lines = text.split('\n');
      expect(lines.length, 3);
      expect(lines[0], contains('line one'));
      expect(lines[1], contains('line two'));
      expect(lines[2], contains('line three'));
    });

    test('exportText with minLevel filters lower levels', () {
      logger.debug('cat', 'debug entry');
      logger.info('cat', 'info entry');
      logger.warn('cat', 'warn entry');
      logger.error('cat', 'error entry');

      final text = logger.exportText(minLevel: LogLevel.warn);
      expect(text, contains('warn entry'));
      expect(text, contains('error entry'));
      expect(text, isNot(contains('debug entry')));
      expect(text, isNot(contains('info entry')));
    });
  });

  group('AppLogger — structured data', () {
    test('log snapshots unsupported values into JSON-safe data', () {
      final mutableList = <Object?>[
        double.infinity,
        <Object, Object?>{1: const _OpaqueLogValue()},
      ];
      final mutableData = <String, Object?>{
        'when': DateTime.utc(2024, 1, 2, 3, 4, 5),
        'nan': double.nan,
        'opaque': const _OpaqueLogValue(),
        'nested': mutableList,
      };

      expect(
        () => logger.log('diagnostic', 'captures data', data: mutableData),
        returnsNormally,
      );

      mutableData['opaque'] = 'changed after log';
      mutableList[0] = 'changed after log';

      final decoded = jsonDecode(logger.exportJson(pretty: false)) as List;
      final entry = decoded.single as Map<String, dynamic>;
      final data = entry['data'] as Map<String, dynamic>;

      expect(data['when'], '2024-01-02T03:04:05.000Z');
      expect(data['nan'], 'NaN');
      expect(data['opaque'], 'opaque-log-value');
      expect(data['nested'], [
        'Infinity',
        {'1': 'opaque-log-value'},
      ]);
    });
  });

  group('AppLogger — exportJson', () {
    test('exportJson returns valid JSON array', () {
      logger.log('render', 'gpu frame');
      logger.log('action', 'user tapped');

      final json = logger.exportJson();
      final decoded = jsonDecode(json);
      expect(decoded, isA<List>());
      expect((decoded as List).length, 2);
    });

    test('exportJson entries contain expected keys', () {
      logger.log('render', 'test', data: {'frames': 42});

      final decoded = jsonDecode(logger.exportJson()) as List;
      final entry = decoded.first as Map<String, dynamic>;
      expect(entry['level'], isNotNull);
      expect(entry['cat'], isNotNull);
      expect(entry['msg'], isNotNull);
      expect(entry['t'], isNotNull);
      expect(entry['data'], {'frames': 42});
    });

    test('exportJson with minLevel filters entries', () {
      logger.debug('cat', 'skip me');
      logger.error('cat', 'keep me');

      final decoded =
          jsonDecode(logger.exportJson(minLevel: LogLevel.error)) as List;
      expect(decoded.length, 1);
      expect((decoded.first as Map)['msg'], 'keep me');
    });

    test('exportJson pretty=false returns compact JSON', () {
      logger.log('cat', 'compact');
      final json = logger.exportJson(pretty: false);
      // Compact JSON has no newlines
      expect(json, isNot(contains('\n')));
    });
  });

  group('AppLogger — clear', () {
    test('clear removes all entries', () async {
      logger.log('a', 'one');
      logger.log('b', 'two');
      expect(logger.length, 2);

      await logger.clearLog();
      expect(logger.length, 0);
      expect(logger.entries, isEmpty);
    });

    test('clearLog notifies listeners', () async {
      logger.log('a', 'entry');
      int notifyCount = 0;
      logger.addListener(() => notifyCount++);

      await logger.clearLog();
      expect(notifyCount, 1);
    });

    test('clear (sync) notifies listeners', () {
      logger.log('a', 'entry');
      int notifyCount = 0;
      logger.addListener(() => notifyCount++);

      logger.clear();
      expect(notifyCount, 1);
    });

    test('log notifies listeners', () {
      int notifyCount = 0;
      logger.addListener(() => notifyCount++);

      logger.log('cat', 'msg');
      expect(notifyCount, 1);
    });
  });

  group('LogEntry.toLogLine', () {
    test('formats correctly with HH:MM:SS.mmm prefix', () {
      final entry = LogEntry(
        timestamp: DateTime(2024, 1, 15, 9, 5, 3, 42),
        level: LogLevel.info,
        category: 'render',
        message: 'hello world',
      );

      final line = entry.toLogLine();
      expect(line, startsWith('[09:05:03.042]'));
      expect(line, contains('[info]'));
      expect(line, contains('[render]'));
      expect(line, contains('hello world'));
    });

    test('toLogLine includes JSON-encoded data when present', () {
      final entry = LogEntry(
        timestamp: DateTime(2024, 6, 1, 12, 0, 0, 0),
        level: LogLevel.warn,
        category: 'gpu',
        message: 'health check',
        data: {'status': 'failed', 'code': 3},
      );

      final line = entry.toLogLine();
      expect(line, contains('"status":"failed"'));
      expect(line, contains('"code":3'));
    });

    test('toLogLine has no data suffix when data is null', () {
      final entry = LogEntry(
        timestamp: DateTime(2024, 6, 1, 12, 0, 0, 0),
        level: LogLevel.debug,
        category: 'action',
        message: 'tap',
      );

      final line = entry.toLogLine();
      // Should end with the message, no trailing data
      expect(line, endsWith('tap'));
    });

    test('toLogLine level ordering: debug < info < warn < error', () {
      expect(LogLevel.debug.index, lessThan(LogLevel.info.index));
      expect(LogLevel.info.index, lessThan(LogLevel.warn.index));
      expect(LogLevel.warn.index, lessThan(LogLevel.error.index));
    });
  });

  group('LogEntry — disk serialisation', () {
    test('toDiskJson uses required keys', () {
      final entry = LogEntry(
        timestamp: DateTime(2024, 3, 10, 8, 0, 0),
        level: LogLevel.warn,
        category: 'render',
        message: 'slow frame',
      );
      final json = entry.toDiskJson();
      expect(json['timestamp'], isA<String>());
      expect(json['level'], 'warn');
      expect(json['tag'], 'render');
      expect(json['message'], 'slow frame');
    });

    test('fromDiskJson round-trips correctly', () {
      final original = LogEntry(
        timestamp: DateTime(2025, 6, 15, 10, 30, 45, 123),
        level: LogLevel.error,
        category: 'gpu',
        message: 'out of memory',
      );
      final json = original.toDiskJson();
      final restored = LogEntry.fromDiskJson(json);

      expect(restored.timestamp.toIso8601String(),
          original.timestamp.toIso8601String());
      expect(restored.level, original.level);
      expect(restored.category, original.category);
      expect(restored.message, original.message);
    });

    test('fromDiskJson with unknown level falls back to info', () {
      final json = {
        'timestamp': DateTime.now().toIso8601String(),
        'level': 'unknown_level',
        'tag': 'test',
        'message': 'msg',
      };
      final entry = LogEntry.fromDiskJson(json);
      expect(entry.level, LogLevel.info);
    });
  });

  group('LogDiskRotationPolicy', () {
    test('keeps newest non-empty lines in chronological order', () {
      final plan = LogDiskRotationPolicy.plan(
        lines: const ['', 'old', 'middle', 'new'],
        maxEntries: 2,
        maxBytes: 1000,
      );

      expect(plan.keptLines, ['middle', 'new']);
      expect(plan.nonEmptyLineCount, 3);
      expect(plan.shouldRewrite, isTrue);
      expect(plan.serializeKeptLines(), 'middle\nnew\n');
    });

    test('counts UTF-8 bytes, not UTF-16 code units, for disk cap', () {
      const older = 'é';
      const newest = '🔥';
      final maxBytes = utf8.encode('$newest\n').length;

      final plan = LogDiskRotationPolicy.plan(
        lines: const [older, newest],
        maxEntries: 10,
        maxBytes: maxBytes,
      );

      expect(plan.keptLines, [newest]);
      expect(plan.keptUtf8Bytes, lessThanOrEqualTo(maxBytes));
      expect(plan.shouldRewrite, isTrue);
    });
  });

  group('AppLogger — file persistence (temp directory)', () {
    late Directory tempDir;
    late File logFile;

    setUp(() async {
      tempDir = await Directory.systemTemp.createTemp('app_logger_test_');
      logFile = File('${tempDir.path}/fractal_forge_logs.jsonl');
    });

    tearDown(() async {
      await tempDir.delete(recursive: true);
    });

    test('_loadFromDisk populates ring buffer from existing JSONL', () async {
      // Write two pre-existing JSONL entries.
      final lines = [
        jsonEncode({
          'timestamp': '2024-01-01T10:00:00.000',
          'level': 'info',
          'tag': 'render',
          'message': 'loaded from disk',
        }),
        jsonEncode({
          'timestamp': '2024-01-01T10:00:01.000',
          'level': 'warn',
          'tag': 'gpu',
          'message': 'second entry',
        }),
      ];
      await logFile.writeAsString(lines.map((l) => '$l\n').join());

      // Parse directly via fromDiskJson to verify the round-trip.
      final readBack = await logFile.readAsLines();
      final parsed = readBack
          .where((l) => l.trim().isNotEmpty)
          .map((l) =>
              LogEntry.fromDiskJson(jsonDecode(l) as Map<String, dynamic>))
          .toList();

      expect(parsed.length, 2);
      expect(parsed[0].message, 'loaded from disk');
      expect(parsed[0].category, 'render');
      expect(parsed[0].level, LogLevel.info);
      expect(parsed[1].message, 'second entry');
      expect(parsed[1].level, LogLevel.warn);
    });

    test('toDiskJson produces valid JSONL-parseable output', () {
      final entry = LogEntry(
        timestamp: DateTime(2025, 1, 1, 0, 0, 0),
        level: LogLevel.debug,
        category: 'action',
        message: 'test message',
      );
      final line = jsonEncode(entry.toDiskJson());
      // Must be valid JSON and single-line.
      expect(() => jsonDecode(line), returnsNormally);
      expect(line, isNot(contains('\n')));
    });

    test('malformed JSONL lines are skipped gracefully', () {
      const bad = '{"timestamp": "not-a-date", bad json}';
      expect(
        () => LogEntry.fromDiskJson(jsonDecode(
                '{"timestamp":"2024-01-01T00:00:00.000","level":"info","tag":"x","message":"y"}')
            as Map<String, dynamic>),
        returnsNormally,
      );
      // Malformed JSON should throw during jsonDecode — catch is in _loadFromDisk.
      expect(() => jsonDecode(bad), throwsA(isA<FormatException>()));
    });
  });
}

// A small lexer for a restricted Fractint-like .frm subset.
//
// Supported tokens (initial subset):
// - identifiers: [A-Za-z_][A-Za-z0-9_]*
// - numbers: 123, 1.23, .5, 1e-3
// - punctuation: { } ( ) , : = + - * /
// - comments: ; to end of line

enum FrmTokKind {
  ident,
  number,
  lBrace,
  rBrace,
  lParen,
  rParen,
  comma,
  colon,
  eq,
  plus,
  minus,
  star,
  slash,
  newline,
  eof,
}

final class FrmTok {
  const FrmTok(this.kind, this.lexeme, this.offset);

  final FrmTokKind kind;
  final String lexeme;
  final int offset;

  @override
  String toString() => '$kind("$lexeme")@$offset';
}

final class FrmLexer {
  FrmLexer(this.src);

  final String src;
  int _i = 0;

  List<FrmTok> tokenize() {
    final out = <FrmTok>[];
    while (true) {
      final tok = _next();
      out.add(tok);
      if (tok.kind == FrmTokKind.eof) return out;
    }
  }

  FrmTok _next() {
    _skipSpaces();
    if (_i >= src.length) return FrmTok(FrmTokKind.eof, '', _i);

    final c = src.codeUnitAt(_i);

    // newline
    if (c == 0x0A) {
      _i++;
      return FrmTok(FrmTokKind.newline, '\n', _i - 1);
    }
    if (c == 0x0D) {
      // CRLF or CR
      final start = _i;
      _i++;
      if (_i < src.length && src.codeUnitAt(_i) == 0x0A) _i++;
      return FrmTok(FrmTokKind.newline, '\n', start);
    }

    // comment ;...
    if (c == 0x3B) {
      while (_i < src.length) {
        final cc = src.codeUnitAt(_i);
        if (cc == 0x0A || cc == 0x0D) break;
        _i++;
      }
      // emit newline separately in next call
      return _next();
    }

    switch (c) {
      case 0x7B: // {
        _i++;
        return FrmTok(FrmTokKind.lBrace, '{', _i - 1);
      case 0x7D: // }
        _i++;
        return FrmTok(FrmTokKind.rBrace, '}', _i - 1);
      case 0x28: // (
        _i++;
        return FrmTok(FrmTokKind.lParen, '(', _i - 1);
      case 0x29: // )
        _i++;
        return FrmTok(FrmTokKind.rParen, ')', _i - 1);
      case 0x2C: // ,
        _i++;
        return FrmTok(FrmTokKind.comma, ',', _i - 1);
      case 0x3A: // :
        _i++;
        return FrmTok(FrmTokKind.colon, ':', _i - 1);
      case 0x3D: // =
        _i++;
        return FrmTok(FrmTokKind.eq, '=', _i - 1);
      case 0x2B: // +
        _i++;
        return FrmTok(FrmTokKind.plus, '+', _i - 1);
      case 0x2D: // -
        _i++;
        return FrmTok(FrmTokKind.minus, '-', _i - 1);
      case 0x2A: // *
        _i++;
        return FrmTok(FrmTokKind.star, '*', _i - 1);
      case 0x2F: // /
        _i++;
        return FrmTok(FrmTokKind.slash, '/', _i - 1);
    }

    if (_isDigit(c) || c == 0x2E /* . */) {
      return _number();
    }

    if (_isAlpha(c) || c == 0x5F /* _ */) {
      return _ident();
    }

    throw FormatException('Unexpected character: ${String.fromCharCode(c)}', src, _i);
  }

  void _skipSpaces() {
    while (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (c == 0x20 || c == 0x09) {
        _i++;
        continue;
      }
      break;
    }
  }

  FrmTok _ident() {
    final start = _i;
    _i++;
    while (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (_isAlphaNum(c) || c == 0x5F) {
        _i++;
      } else {
        break;
      }
    }
    return FrmTok(FrmTokKind.ident, src.substring(start, _i), start);
  }

  FrmTok _number() {
    final start = _i;

    bool sawDigit = false;

    // int part or leading '.'
    if (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
      sawDigit = true;
      while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
        _i++;
      }
    }

    // decimal
    if (_i < src.length && src.codeUnitAt(_i) == 0x2E /* . */) {
      _i++;
      while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
        sawDigit = true;
        _i++;
      }
    }

    if (!sawDigit) {
      throw FormatException('Invalid number', src, start);
    }

    // exponent
    if (_i < src.length) {
      final c = src.codeUnitAt(_i);
      if (c == 0x65 /* e */ || c == 0x45 /* E */) {
        _i++;
        if (_i < src.length) {
          final s = src.codeUnitAt(_i);
          if (s == 0x2B /* + */ || s == 0x2D /* - */) _i++;
        }
        final expStart = _i;
        while (_i < src.length && _isDigit(src.codeUnitAt(_i))) {
          _i++;
        }
        if (expStart == _i) {
          throw FormatException('Invalid exponent', src, expStart);
        }
      }
    }

    return FrmTok(FrmTokKind.number, src.substring(start, _i), start);
  }

  static bool _isDigit(int c) => c >= 0x30 && c <= 0x39;
  static bool _isAlpha(int c) => (c >= 0x41 && c <= 0x5A) || (c >= 0x61 && c <= 0x7A);
  static bool _isAlphaNum(int c) => _isAlpha(c) || _isDigit(c);
}

import 'frm_ast.dart';
import 'frm_lexer.dart';
import 'frm_number_literal.dart';

/// Parser for a small Fractint-style .frm subset.
///
/// Current supported subset:
/// - Multiple formulas per file.
/// - `name { <init-stmts> : <iter-stmts> }`
/// - Stmts: `<ident> = <expr>` separated by newlines.
/// - Expr: numbers, identifiers, (re,im) complex literals, + - * / with parens.
///
/// This is intentionally small; we’ll extend it iteratively with functions,
/// power, comparisons, and bailout conditions once golden iteration tests are in.
bool isFrmStatementBoundary(FrmTokKind kind) =>
    kind == FrmTokKind.newline ||
    kind == FrmTokKind.colon ||
    kind == FrmTokKind.rBrace ||
    kind == FrmTokKind.eof;

bool isFrmFormulaBodyEnd(FrmTokKind kind) =>
    kind == FrmTokKind.rBrace || kind == FrmTokKind.eof;

final class FrmParser {
  FrmParser(String src) : _toks = FrmLexer(src).tokenize();

  final List<FrmTok> _toks;
  int _p = 0;

  FrmFile parseFile() {
    final formulas = <FrmFormula>[];
    _skipNewlines();
    while (!_peekIs(FrmTokKind.eof)) {
      formulas.add(_parseFormula());
      _skipNewlines();
    }
    return FrmFile(formulas);
  }

  FrmFormula _parseFormula() {
    final nameTok = _expect(FrmTokKind.ident, 'Expected formula name');
    _skipNewlines();
    _expect(FrmTokKind.lBrace, 'Expected "{" after formula name');

    final init = <FrmStmt>[];
    final iter = <FrmStmt>[];

    _skipNewlines();
    while (!_peekIs(FrmTokKind.colon)) {
      _expectInitSectionContinues();
      final stmt = _parseStmt();
      init.add(stmt);
      _skipNewlines();
    }

    _expect(FrmTokKind.colon, 'Expected ":" separating init/iter');
    _skipNewlines();

    while (!_peekIs(FrmTokKind.rBrace)) {
      if (_peekIs(FrmTokKind.eof)) {
        throw FormatException('Unterminated formula body', '', _peek().offset);
      }
      final stmt = _parseStmt();
      iter.add(stmt);
      _skipNewlines();
    }

    _expect(FrmTokKind.rBrace, 'Expected "}"');

    return FrmFormula(name: nameTok.lexeme, init: init, iter: iter);
  }

  FrmStmt _parseStmt() {
    final name = _expect(FrmTokKind.ident, 'Expected identifier').lexeme;
    _expect(FrmTokKind.eq, 'Expected "="');
    final expr = _parseExpr();
    _expectStmtBoundary();
    return FrmAssign(name, expr);
  }

  void _expectInitSectionContinues() {
    final tok = _peek();
    if (!isFrmFormulaBodyEnd(tok.kind)) return;
    if (tok.kind == FrmTokKind.eof) {
      throw FormatException('Unterminated formula body', '', tok.offset);
    }
    throw FormatException('Expected ":" in formula body', '', tok.offset);
  }

  void _expectStmtBoundary() {
    final tok = _peek();
    if (!isFrmStatementBoundary(tok.kind)) {
      throw FormatException('Expected newline after statement', '', tok.offset);
    }
  }

  FrmExpr _parseExpr() => _parseAddSub();

  FrmExpr _parseAddSub() {
    var expr = _parseMulDiv();
    while (true) {
      if (_match(FrmTokKind.plus)) {
        expr = FrmBinary(FrmBinaryOp.add, expr, _parseMulDiv());
        continue;
      }
      if (_match(FrmTokKind.minus)) {
        expr = FrmBinary(FrmBinaryOp.sub, expr, _parseMulDiv());
        continue;
      }
      return expr;
    }
  }

  FrmExpr _parseMulDiv() {
    var expr = _parsePrimary();
    while (true) {
      if (_match(FrmTokKind.star)) {
        expr = FrmBinary(FrmBinaryOp.mul, expr, _parsePrimary());
        continue;
      }
      if (_match(FrmTokKind.slash)) {
        expr = FrmBinary(FrmBinaryOp.div, expr, _parsePrimary());
        continue;
      }
      return expr;
    }
  }

  FrmExpr _parsePrimary() {
    if (_match(FrmTokKind.number)) {
      return FrmNumber(FrmNumberLiteral.fromToken(_prev()).parseFinite());
    }

    if (_match(FrmTokKind.ident)) {
      return FrmVar(_prev().lexeme);
    }

    if (_match(FrmTokKind.lParen)) {
      // Could be (expr) or (re,im)
      final first = _parseExpr();
      if (_match(FrmTokKind.comma)) {
        final second = _parseExpr();
        _expect(FrmTokKind.rParen, 'Expected ")"');
        return FrmComplexLiteral(first, second);
      }
      _expect(FrmTokKind.rParen, 'Expected ")"');
      return first;
    }

    if (_match(FrmTokKind.minus)) {
      // unary minus: -x  => (0 - x)
      return FrmBinary(FrmBinaryOp.sub, const FrmNumber(0), _parsePrimary());
    }

    throw FormatException('Expected expression', '', _peek().offset);
  }

  void _skipNewlines() {
    while (_match(FrmTokKind.newline)) {}
  }

  bool _match(FrmTokKind kind) {
    if (_peekIs(kind)) {
      _p++;
      return true;
    }
    return false;
  }

  FrmTok _expect(FrmTokKind kind, String msg) {
    final tok = _peek();
    if (tok.kind != kind) {
      throw FormatException(msg, '', tok.offset);
    }
    _p++;
    return tok;
  }

  FrmTok _peek() => _toks[_p];
  FrmTok _prev() => _toks[_p - 1];
  bool _peekIs(FrmTokKind k) => _peek().kind == k;
}

import 'complex.dart';

sealed class FrmExpr {
  const FrmExpr();

  Complex eval(FrmEvalContext ctx);
}

final class FrmNumber extends FrmExpr {
  const FrmNumber(this.value);

  final double value;

  @override
  Complex eval(FrmEvalContext ctx) => Complex(value, 0);
}

final class FrmComplexLiteral extends FrmExpr {
  const FrmComplexLiteral(this.re, this.im);

  final FrmExpr re;
  final FrmExpr im;

  @override
  Complex eval(FrmEvalContext ctx) {
    final r = evalFrmRealScalarComponent(re, ctx, componentName: 'real');
    final i = evalFrmRealScalarComponent(im, ctx, componentName: 'imaginary');
    return Complex(r, i);
  }
}

/// Evaluates one component of a `(real, imaginary)` literal.
///
/// FRM complex literal components are scalar slots. Silently taking `.re` from
/// a complex-valued expression drops data and makes replay depend on an
/// undocumented truncation rule, so reject that shape at the evaluation seam.
double evalFrmRealScalarComponent(
  FrmExpr expr,
  FrmEvalContext ctx, {
  required String componentName,
}) {
  final value = expr.eval(ctx);
  if (value.im == 0.0) return value.re;
  throw StateError(
    'Complex literal components must evaluate to real scalars; '
    '$componentName component was $value',
  );
}

final class FrmVar extends FrmExpr {
  const FrmVar(this.name);

  final String name;

  @override
  Complex eval(FrmEvalContext ctx) =>
      ctx.vars[name] ?? (throw StateError('Unknown var: $name'));
}

enum FrmBinaryOp { add, sub, mul, div }

final class FrmBinary extends FrmExpr {
  const FrmBinary(this.op, this.left, this.right);

  final FrmBinaryOp op;
  final FrmExpr left;
  final FrmExpr right;

  @override
  Complex eval(FrmEvalContext ctx) {
    final a = left.eval(ctx);
    final b = right.eval(ctx);
    return switch (op) {
      FrmBinaryOp.add => a + b,
      FrmBinaryOp.sub => a - b,
      FrmBinaryOp.mul => a * b,
      FrmBinaryOp.div => a / b,
    };
  }
}

sealed class FrmStmt {
  const FrmStmt();

  void run(FrmEvalContext ctx);
}

final class FrmAssign extends FrmStmt {
  const FrmAssign(this.name, this.expr);

  final String name;
  final FrmExpr expr;

  @override
  void run(FrmEvalContext ctx) {
    ctx.vars[name] = expr.eval(ctx);
  }
}

/// Execution context for a single pixel / iteration.
final class FrmEvalContext {
  FrmEvalContext({required this.vars});

  final Map<String, Complex> vars;
}

final class FrmFormula {
  FrmFormula({
    required this.name,
    required Iterable<FrmStmt> init,
    required Iterable<FrmStmt> iter,
  })  : init = List.unmodifiable(init),
        iter = List.unmodifiable(iter);

  final String name;

  /// Statements before `:`
  final List<FrmStmt> init;

  /// Statements after `:`
  final List<FrmStmt> iter;
}

final class FrmFile {
  FrmFile(Iterable<FrmFormula> formulas)
      : formulas = List.unmodifiable(formulas);

  final List<FrmFormula> formulas;
}

import 'package:flutter_fractals/features/formulas/frm/complex.dart';
import 'package:flutter_fractals/features/formulas/frm/frm_ast.dart';
import 'package:flutter_fractals/features/formulas/frm/frm_parser.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('FrmParser (subset)', () {
    test('parses multiple formulas with init/iter sections', () {
      const src = r'''
; comment
Mandelbrot {
  z = (0,0)
  c = pixel
:
  z = z*z + c
}

Julia {
  z = pixel
  c = (0.285, 0.01)
:
  z = z*z + c
}
''';

      final file = FrmParser(src).parseFile();
      expect(
          file.formulas.map((f) => f.name).toList(), ['Mandelbrot', 'Julia']);
      expect(file.formulas[0].init.length, 2);
      expect(file.formulas[0].iter.length, 1);
    });

    test('rejects adjacent assignments without a newline separator', () {
      const src = r'''
Test {
  z = (0,0) c = pixel
:
  z = z*z + c
}
''';

      expect(
        () => FrmParser(src).parseFile(),
        throwsA(
          isA<FormatException>().having(
            (e) => e.message,
            'message',
            'Expected newline after statement',
          ),
        ),
      );
    });

    test('reports unterminated body when EOF appears before section separator',
        () {
      const src = r'''
Test {
  z = (0,0)
''';

      expect(
        () => FrmParser(src).parseFile(),
        throwsA(
          isA<FormatException>().having(
            (e) => e.message,
            'message',
            'Unterminated formula body',
          ),
        ),
      );
    });

    test('rejects complex-valued components inside complex literals', () {
      const src = r'''
Test {
  z = ((1,2), 3)
:
  z = z
}
''';

      final formula = FrmParser(src).parseFile().formulas.single;
      final ctx = FrmEvalContext(vars: {'pixel': const Complex(0, 0)});

      expect(
        () => formula.init.single.run(ctx),
        throwsA(
          isA<StateError>().having(
            (e) => e.message,
            'message',
            contains(
                'Complex literal components must evaluate to real scalars'),
          ),
        ),
      );
    });

    test('rejects complex division by zero before leaking non-finite state',
        () {
      const src = r'''
Test {
  z = (1,0) / (0,0)
:
  z = z
}
''';

      final formula = FrmParser(src).parseFile().formulas.single;
      final ctx = FrmEvalContext(vars: {'pixel': const Complex(0, 0)});

      expect(
        () => formula.init.single.run(ctx),
        throwsA(
          isA<StateError>().having(
            (e) => e.message,
            'message',
            contains('Complex divisor must be finite and non-zero'),
          ),
        ),
      );
      expect(ctx.vars, isNot(contains('z')));
    });

    test('rejects arithmetic overflow before leaking non-finite state', () {
      const src = r'''
Test {
  z = (1e308,0) * (1e308,0)
:
  z = z
}
''';

      final formula = FrmParser(src).parseFile().formulas.single;
      final ctx = FrmEvalContext(vars: {'pixel': const Complex(0, 0)});

      expect(
        () => formula.init.single.run(ctx),
        throwsA(
          isA<StateError>().having(
            (e) => e.message,
            'message',
            contains('Complex arithmetic result must be finite'),
          ),
        ),
      );
      expect(ctx.vars, isNot(contains('z')));
    });

    test('rejects non-finite numeric literals before evaluation', () {
      const src = r'''
Test {
  z = 1e999
:
  z = z
}
''';

      expect(
        () => FrmParser(src).parseFile(),
        throwsA(
          isA<FormatException>().having(
            (e) => e.message,
            'message',
            'Numeric literal must be finite',
          ),
        ),
      );
    });

    test('evaluates a simple iter statement', () {
      const src = r'''
Test {
  z = (0,0)
  c = (1,0)
:
  z = z*z + c
}
''';

      final formula = FrmParser(src).parseFile().formulas.single;
      final ctx = FrmEvalContext(vars: {
        'z': const Complex(0, 0),
        'c': const Complex(1, 0),
        'pixel': const Complex(0, 0),
      });

      for (final s in formula.init) {
        s.run(ctx);
      }
      // z=(0,0), c=(1,0)
      expect(ctx.vars['z']!.re, 0);
      expect(ctx.vars['c']!.re, 1);

      for (final s in formula.iter) {
        s.run(ctx);
      }
      // z = 0*0 + 1
      expect(ctx.vars['z']!.re, closeTo(1, 1e-12));
      expect(ctx.vars['z']!.im, closeTo(0, 1e-12));
    });

    test('returns immutable parse result lists', () {
      const src = r'''
Test {
  z = (0,0)
:
  z = z*z
}
''';

      final file = FrmParser(src).parseFile();
      final formula = file.formulas.single;

      expect(
        () => file.formulas.add(
          FrmFormula(name: 'Other', init: const [], iter: const []),
        ),
        throwsUnsupportedError,
      );
      expect(
        () => formula.init.add(const FrmAssign('c', FrmVar('pixel'))),
        throwsUnsupportedError,
      );
      expect(
        () => formula.iter.clear(),
        throwsUnsupportedError,
      );
    });
  });
}

/// Minimal complex number type for CPU-side formula evaluation.
///
/// We keep this tiny and allocation-light so we can evolve it into a proper
/// iteration engine later.
class Complex {
  const Complex(this.re, this.im);

  final double re;
  final double im;

  Complex operator +(Complex other) => ComplexArithmeticContract.finiteResult(
      'add', Complex(re + other.re, im + other.im));
  Complex operator -(Complex other) => ComplexArithmeticContract.finiteResult(
      'subtract', Complex(re - other.re, im - other.im));

  Complex operator *(Complex other) => ComplexArithmeticContract.finiteResult(
        'multiply',
        Complex(
          re * other.re - im * other.im,
          re * other.im + im * other.re,
        ),
      );

  Complex operator /(Complex other) {
    final denom = ComplexDivisionContract.denominatorFor(other);
    return ComplexArithmeticContract.finiteResult(
      'divide',
      Complex(
        (re * other.re + im * other.im) / denom,
        (im * other.re - re * other.im) / denom,
      ),
    );
  }

  bool get isFinite => re.isFinite && im.isFinite;

  Complex scale(double s) =>
      ComplexArithmeticContract.finiteResult('scale', Complex(re * s, im * s));

  double abs2() => re * re + im * im;

  @override
  String toString() => '($re,$im)';
}

/// Replayable finite-result contract for complex arithmetic.
///
/// FRM numeric literals are finite, but finite operands can still overflow
/// during arithmetic. Keep that invariant at the arithmetic seam so evaluator
/// tests can replay malformed formulas before non-finite state enters vars.
final class ComplexArithmeticContract {
  const ComplexArithmeticContract._();

  static Complex finiteResult(String operation, Complex result) {
    if (result.isFinite) return result;
    throw StateError(
      'Complex arithmetic result must be finite after $operation: $result',
    );
  }
}

/// Replayable denominator contract for complex division.
///
/// FRM evaluation is finite-state: a zero or non-finite divisor previously
/// leaked Infinity/NaN into the variable map. Keep that invariant at the
/// arithmetic seam so parser/evaluator tests can replay malformed formulas.
final class ComplexDivisionContract {
  const ComplexDivisionContract._();

  static double denominatorFor(Complex divisor) {
    final denominator = divisor.abs2();
    if (!divisor.isFinite || denominator == 0.0 || denominator.isNaN) {
      throw StateError(
        'Complex divisor must be finite and non-zero: $divisor',
      );
    }
    return denominator;
  }
}

import 'frm_lexer.dart';

/// Replayable numeric-literal contract for the FRM subset.
///
/// The lexer validates numeric syntax, but `double.parse` can still promote
/// very large exponents (for example `1e999`) to Infinity. FRM evaluation only
/// has finite complex scalars, so reject non-finite literals at the parser
/// boundary before they become hidden NaN/Infinity state.
final class FrmNumberLiteral {
  const FrmNumberLiteral({required this.lexeme, required this.offset});

  factory FrmNumberLiteral.fromToken(FrmTok token) {
    assert(token.kind == FrmTokKind.number, 'expected number token');
    return FrmNumberLiteral(lexeme: token.lexeme, offset: token.offset);
  }

  final String lexeme;
  final int offset;

  double parseFinite() {
    final value = double.parse(lexeme);
    if (value.isFinite) return value;
    throw FormatException('Numeric literal must be finite', lexeme, offset);
  }
}

import 'dart:math' as math;
import 'dart:ui';

/// Replayable geometry for the 2D fractal minimap.
///
/// The widget paints a tiny overview and an indicator for the currently visible
/// renderer viewport. Keeping the coordinate math pure lets tests characterize
/// assumptions about zoom samples, minimap size, and renderer aspect ratio
/// without relying on a canvas paint pass.
final class MiniMapGeometry {
  static const double defaultZoom = 1.0;
  static const double minimumIndicatorDimension = 4.0;

  /// Fractal-plane span represented by the minimap overview on each axis.
  static const double overviewWorldSpan = 4.0;

  const MiniMapGeometry._();

  static double normalizeZoom(double zoom) {
    if (!zoom.isFinite || zoom <= 0.0) return defaultZoom;
    return zoom;
  }

  static Offset normalizePan(Offset pan) {
    return Offset(
      pan.dx.isFinite ? pan.dx : 0.0,
      pan.dy.isFinite ? pan.dy : 0.0,
    );
  }

  /// Maps an absolute fractal-plane pan center to minimap pixels.
  static Offset centerForPan({
    required Offset pan,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safePan = normalizePan(pan);
    return Offset(
      width / 2.0 + safePan.dx * width / overviewWorldSpan,
      height / 2.0 + safePan.dy * height / overviewWorldSpan,
    );
  }

  /// Inverse of [centerForPan] for tap-to-pan jumps.
  static Offset panForCenter({
    required Offset center,
    required Size minimapSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    final safeCenter = Offset(
      center.dx.isFinite ? center.dx : width / 2.0,
      center.dy.isFinite ? center.dy : height / 2.0,
    );
    return Offset(
      (safeCenter.dx / width - 0.5) * overviewWorldSpan,
      (safeCenter.dy / height - 0.5) * overviewWorldSpan,
    );
  }

  static Rect viewportRect({
    required Offset pan,
    required double zoom,
    required Size minimapSize,
    required Size viewportSize,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Rect.zero;

    final safePan = normalizePan(pan);
    final safeZoom = normalizeZoom(zoom);
    final safeViewportSize = _positiveFiniteViewportSize(viewportSize);
    final viewportShortSide = math.min(
      safeViewportSize.width,
      safeViewportSize.height,
    );
    final viewportWidthScale = safeViewportSize.width / viewportShortSide;
    final viewportHeightScale = safeViewportSize.height / viewportShortSide;

    final baseViewportWidth = (2.0 / safeZoom) * (width / overviewWorldSpan);
    final baseViewportHeight = (2.0 / safeZoom) * (height / overviewWorldSpan);
    final center = centerForPan(pan: safePan, minimapSize: minimapSize);

    return Rect.fromCenter(
      center: center,
      width: _clampIndicatorDimension(
        baseViewportWidth * viewportWidthScale,
        width,
      ),
      height: _clampIndicatorDimension(
        baseViewportHeight * viewportHeightScale,
        height,
      ),
    );
  }

  static Offset panForTap({
    required Offset localPosition,
    required Size minimapSize,
    required double zoom,
  }) {
    final width = _positiveFiniteOrZero(minimapSize.width);
    final height = _positiveFiniteOrZero(minimapSize.height);
    if (width <= 0.0 || height <= 0.0) return Offset.zero;

    // Pan is an absolute fractal-plane center; zoom changes the viewport
    // indicator size, not which overview coordinate a tap selects.
    return panForCenter(center: localPosition, minimapSize: minimapSize);
  }

  static double _positiveFiniteOrZero(double value) {
    return value.isFinite && value > 0.0 ? value : 0.0;
  }

  static Size _positiveFiniteViewportSize(Size size) {
    if (_positiveFiniteOrZero(size.width) == 0.0 ||
        _positiveFiniteOrZero(size.height) == 0.0) {
      return const Size(1, 1);
    }
    return size;
  }

  static double _clampIndicatorDimension(double value, double extent) {
    final lower = math.min(minimumIndicatorDimension, extent);
    if (!value.isFinite || value <= 0.0) return lower;
    return value.clamp(lower, extent).toDouble();
  }
}

